CREATE TABLE IF NOT EXISTS "notification_events" (
  "id" bigint GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "title_key" character varying NOT NULL DEFAULT '',
  "title" text NOT NULL,
  "message_key" character varying NOT NULL DEFAULT '',
  "message" text NOT NULL,
  "severity" character varying NOT NULL,
  "category" character varying NOT NULL,
  "source_module" character varying NOT NULL,
  "event_type" character varying NOT NULL,
  "resource_type" character varying NOT NULL DEFAULT '',
  "resource_id" character varying NOT NULL DEFAULT '',
  "resource_name" character varying NOT NULL DEFAULT '',
  "navigation_kind" character varying NOT NULL,
  "navigation_payload" jsonb NOT NULL DEFAULT '{}'::jsonb,
  "metadata" jsonb NOT NULL DEFAULT '{}'::jsonb,
  "dedupe_key" character varying NULL,
  "occurred_at" timestamptz NOT NULL,
  "expires_at" timestamptz NULL,
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  PRIMARY KEY ("id")
);

CREATE UNIQUE INDEX IF NOT EXISTS "notification_events_dedupe_key"
  ON "notification_events" ("dedupe_key")
  WHERE "dedupe_key" IS NOT NULL;
CREATE INDEX IF NOT EXISTS "notification_events_occurred_at"
  ON "notification_events" ("occurred_at" DESC, "id" DESC);
CREATE INDEX IF NOT EXISTS "notification_events_source_module"
  ON "notification_events" ("source_module");
CREATE INDEX IF NOT EXISTS "notification_events_category_severity"
  ON "notification_events" ("category", "severity");

CREATE TABLE IF NOT EXISTS "notification_deliveries" (
  "id" bigint GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "event_id" bigint NOT NULL,
  "recipient_user_id" bigint NOT NULL,
  "target_type" character varying NOT NULL,
  "target_ref" character varying NOT NULL DEFAULT '',
  "read_at" timestamptz NULL,
  "deleted_at" timestamptz NULL,
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  PRIMARY KEY ("id"),
  CONSTRAINT "notification_deliveries_event_id_fkey"
    FOREIGN KEY ("event_id") REFERENCES "notification_events" ("id") ON DELETE CASCADE
);

CREATE INDEX IF NOT EXISTS "notification_deliveries_recipient_created"
  ON "notification_deliveries" ("recipient_user_id", "created_at" DESC, "id" DESC)
  WHERE "deleted_at" IS NULL;
CREATE INDEX IF NOT EXISTS "notification_deliveries_unread"
  ON "notification_deliveries" ("recipient_user_id", "id" DESC)
  WHERE "read_at" IS NULL AND "deleted_at" IS NULL;
CREATE INDEX IF NOT EXISTS "notification_deliveries_event_id"
  ON "notification_deliveries" ("event_id");
CREATE UNIQUE INDEX IF NOT EXISTS "notification_deliveries_event_recipient"
  ON "notification_deliveries" ("event_id", "recipient_user_id");
CREATE INDEX IF NOT EXISTS "notification_deliveries_target"
  ON "notification_deliveries" ("target_type", "target_ref");

COMMENT ON TABLE "notification_events" IS '通知中心事件事实表';
COMMENT ON COLUMN "notification_events"."id" IS '通知事件事实主键';
COMMENT ON COLUMN "notification_events"."title_key" IS '可选标题消息键';
COMMENT ON COLUMN "notification_events"."title" IS '发布时标题快照';
COMMENT ON COLUMN "notification_events"."message_key" IS '可选正文消息键';
COMMENT ON COLUMN "notification_events"."message" IS '发布时正文快照';
COMMENT ON COLUMN "notification_events"."severity" IS '通知级别 typed contract';
COMMENT ON COLUMN "notification_events"."category" IS '通知分类 typed contract';
COMMENT ON COLUMN "notification_events"."source_module" IS '来源模块标识';
COMMENT ON COLUMN "notification_events"."event_type" IS '来源模块事件类型';
COMMENT ON COLUMN "notification_events"."resource_type" IS '业务资源类型';
COMMENT ON COLUMN "notification_events"."resource_id" IS '业务资源标识';
COMMENT ON COLUMN "notification_events"."resource_name" IS '业务资源名称';
COMMENT ON COLUMN "notification_events"."navigation_kind" IS '结构化跳转类型 typed contract';
COMMENT ON COLUMN "notification_events"."navigation_payload" IS '结构化跳转载荷';
COMMENT ON COLUMN "notification_events"."metadata" IS '来源模块提供的附加元数据';
COMMENT ON COLUMN "notification_events"."dedupe_key" IS '来源模块提供的幂等键';
COMMENT ON COLUMN "notification_events"."occurred_at" IS '业务事件发生时间';
COMMENT ON COLUMN "notification_events"."expires_at" IS '通知事实过期时间';
COMMENT ON COLUMN "notification_events"."created_at" IS '通知事实创建时间';

COMMENT ON TABLE "notification_deliveries" IS '通知中心用户投递状态表';
COMMENT ON COLUMN "notification_deliveries"."id" IS '通知投递状态主键';
COMMENT ON COLUMN "notification_deliveries"."event_id" IS '通知事件事实 ID';
COMMENT ON COLUMN "notification_deliveries"."recipient_user_id" IS '最终接收用户 ID';
COMMENT ON COLUMN "notification_deliveries"."target_type" IS '投递目标类型 typed contract';
COMMENT ON COLUMN "notification_deliveries"."target_ref" IS '投递目标引用值';
COMMENT ON COLUMN "notification_deliveries"."read_at" IS '用户已读时间';
COMMENT ON COLUMN "notification_deliveries"."deleted_at" IS '用户删除投递时间';
COMMENT ON COLUMN "notification_deliveries"."created_at" IS '投递记录创建时间';
